class Solution:
    def maxHeightOfTriangle(self, red: int, blue: int) -> int:
        # Try both possibilities: starting with red or starting with blue
        max_height = 0
        for start_color, count in [('red', red), ('blue', blue)]:
            r, b = red, blue
            height = 0
            # Alternate colors
            while True:
                if start_color == 'red':
                    if r >= height + 1:
                        r -= height + 1
                        height += 1
                        start_color = 'blue'
                    else:
                        break
                else:
                    if b >= height + 1:
                        b -= height + 1
                        height += 1
                        start_color = 'red'
                    else:
                        break
            max_height = max(max_height, height)
        return max_height
